import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { GroupValidator } from './group.validator';
import { CreateGroupDTO } from './group.dto';
import { AppError } from '../../utils/app-error';

export class GroupController {
  constructor(private readonly groupService: GroupService) {}

  async createGroup(req: Request, res: Response): Promise<void> {
    try {
      const createGroupDto = GroupValidator.validateCreateGroup(req.body);
      const group = await this.groupService.createGroup(createGroupDto);
      res.status(201).json({
        success: true,
        data: group,
        meta: {
          requestId: req.headers['x-request-id'],
          timestamp: new Date().toISOString(),
          version: 'v1',
        },
      });
    } catch (error) {
      const errorCode = error instanceof AppError ? error.code : 'INTERNAL_SERVER_ERROR';
      res.status(500).json({
        success: false,
        error: {
          message: error.message,
          code: errorCode,
        },
      });
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO } from './group.dto';
import { Group } from './group.model';

export class GroupService {
  constructor(private readonly groupRepository: GroupRepository) {}

  async createGroup(dto: CreateGroupDTO): Promise<Group> {
    return this.groupRepository.create(dto);
  }
}

import { Group } from './group.model';
import { CreateGroupDTO } from './group.dto';

export class GroupRepository {
  async create(dto: CreateGroupDTO): Promise<Group> {
    const group = new Group({ ...dto, createdAt: new Date() });
    await group.save();
    return group;
  }
}

import { Schema, model, Document } from 'mongoose';

export interface Group extends Document {
  name: string;
  description: string;
  adminId: Schema.Types.ObjectId;
  members: Schema.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true },
  members: [{ type: Schema.Types.ObjectId, required: true }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now },
});

export const GroupModel = model<Group>('Group', groupSchema);

import { Schema } from 'mongoose';

export interface CreateGroupDTO {
  name: string;
  description: string;
  adminId: Schema.Types.ObjectId;
  members: Schema.Types.ObjectId[];
  telegramChatId?: string;
}

import { z } from 'zod';
import { CreateGroupDTO } from './group.dto';

const createGroupSchema = z.object({
  name: z.string().min(1),
  description: z.string().min(1),
  adminId: z.string().min(1), // Assuming adminId is stringified ObjectId
  members: z.array(z.string().min(1)), // Assuming members are stringified ObjectIds
  telegramChatId: z.string().optional().nullable(),
});

export class GroupValidator {
  static validateCreateGroup(payload: any): CreateGroupDTO {
    return createGroupSchema.parse(payload);
  }
}

export class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(message: string, statusCode: number, code: string) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.string(),
  MONGO_URI: z.string().url(),
  JWT_SECRET: z.string().min(8),
  RATE_LIMIT_MAX: z.number().int().positive(),
  RATE_LIMIT_WINDOW: z.string(),
});

envSchema.parse(process.env);

export default process.env;
